		var urlDetailMode, urlDetailId;
var urlListMode, urlListWF, urlListfil1, urlListfil2, urlListfil3, urlListPage;
var DebugMode=0, DebugEtty;
var winTITLE, winTASK, g_PASO, g_DETAIL_LAYOUT;


///////////////////////////////////////////////////////////////////////////////          
// Control del TITULO
function SetWindowTitle(objWIN, label)
{ 
	if (objWIN) winTITLE=objWIN;
	SetTitle(label);
}                
function RefreshTitle(mode,wf,crc)
{        
	if (mode=="WF") return;

	if (winTITLE && winTITLE.RefreshTitle)
	{      
		winTITLE.RefreshTitle(wf, mode, DebugEtty,crc);
	} else
	{    
		var result = CalcularCRC(DebugMode,DebugEtty,GetProxy().GetCfgResource("start-form-menu"),'',mode,'','','','',wf,'','','','');

		Ctrl("urlTitle").SetURL("../../../ReportViewer.aspx?ut="+GetProxy().UserToken()+"&file=NucleusWF.Base.Ejecucion.ConsolaTitulo.rpt&wf="+wf+"&mode="+mode+"&DEBUG="+DebugMode+"&DEBUGETTY="+DebugEtty+"&crc="+result.GetAttr('crcTitulo'));
	}
}        

///////////////////////////////////////////////////////////////////////////////          
// Control de las TAREAS
function SetWindowTask(objWIN)
{                             
	winTASK=objWIN;
}                
function SetListPage(page)
{
	urlListPage=page;
}
function AutorefreshList()
{ 
	if (winTASK && winTASK.RefreshTaskList)
	{                                     
		winTASK.RefreshTaskList(urlListPage,urlListWF,urlListMode,urlListfil1,urlListfil2,urlListfil3,DebugEtty);
	} else
	{   
	    var result = CalcularCRC(DebugMode,DebugEtty,GetProxy().GetCfgResource("start-form-menu"),urlListMode,'TASK',urlDetailId,g_DETAIL_LAYOUT,g_PASO,'DETAIL',urlListWF,urlListfil1,urlListfil2,urlListfil3,urlListPage);

		Ctrl("urlList").SetURL("../../../ReportViewer.aspx?ut="+GetProxy().UserToken()+"&file=NucleusWF.Base.Ejecucion.ConsolaTareas.rpt&size=8&page="+urlListPage+"&wf="+urlListWF+"&mode="+urlListMode+"&fil="+urlListfil1+"&fil2="+urlListfil2+"&fil3="+urlListfil3+"&DEBUG="+DebugMode+"&DEBUGETTY="+DebugEtty+"&crc="+result.GetAttr('crcTarea'));
	}
}                                      

function RefreshList(mode,wf,fil,fil2,fil3)
{ 
	if (mode=="WF") return;

	urlListMode=mode;
	urlListWF=wf;
	urlListfil1=fil;
	urlListfil2=fil2;
	urlListfil3=fil3;
	urlListPage=1;

	AutorefreshList();
	RefreshDetail(mode,wf);
}



