//EVENTOS
function OnLoad()
{           
	winTITLE=null;   
	winTASK=null;
	urlDetailMode="";
	urlDetailWf="";
	DebugMode=0;
	g_PASO=1;       
	g_DETAIL_LAYOUT="N";

	if (Ctrl("main").GetMode()=="DEBUG") 
	{ 
		DebugMode=1; 
		DebugEtty="";
		internalChangeEtty("");
	} else
	{
		DebugEtty=GetProxy().Etty();
	}

    var result = CalcularCRC(DebugMode,DebugEtty,GetProxy().GetCfgResource("start-form-menu"),'ALL','TASK','','','','','','','','','');

	Ctrl("urlPath" ).SetURL("../../../ReportViewer.aspx?ut="+GetProxy().UserToken()+"&file=NucleusWF.Base.Ejecucion.ConsolaCarpetas.rpt&mode=ALL&menu="+GetProxy().GetCfgResource("start-form-menu")+"&DEBUG="+DebugMode+"&DEBUGETTY="+DebugEtty+"&crc="+result.GetAttr('crcCarpeta'));
	Ctrl("urlTitle").SetURL("../../../ReportViewer.aspx?ut="+GetProxy().UserToken()+"&file=NucleusWF.Base.Ejecucion.ConsolaTitulo.rpt&mode=TASK&wf=&DEBUG="+DebugMode+"&DEBUGETTY="+DebugEtty+"&crc="+result.GetAttr('crcTitulo'));
}      

function CalcularCRC(debugMode,debugEtty,menu,mode,modeTitulo,detailId,show,paso,style,wf,fil,fil2,fil3,page)  
{
   	var	np = GetProxy();
	var nSQL = np.SQLService(); 	
	var qry = Ctrl("main").getResource("qry_crc");	
   	return nSQL.GetXML(qry, "<DATA debugMode='"+debugMode+"' debugEtty='"+debugEtty+"' wf='"+wf+"' menu='"+menu+"' mode='"+mode+"' modeTitulo='"+modeTitulo+"' detailId='"+detailId+"' show='"+show+"' paso='"+paso+"' style='"+style+"' fil='"+fil+"' fil2='"+fil2+"' fil3='"+fil3+"' page='"+page+"'/>");
}

function internalChangeEtty(ettyValue)
{
	if (ettyValue=="") 
		DebugEtty=GetProxy().Etty();
	else
		DebugEtty=ettyValue;

	ETTY=GetProxy().DDOService().GetXML("Nomad.Base.Login.Entidades.ENTIDAD",DebugEtty);
	Ctrl("debugetty").SetXValue("Entidad Actual: "+ETTY.FindElement("ENTIDAD").GetAttr("DES"));
}

function ChangeEtty()
{                
	if (Ctrl("oi_entidad").GetXValue()!="")
	{                                    
		urlDetailMode="";
		urlDetailWf="";

		internalChangeEtty(Ctrl("oi_entidad").GetXValue());

   	 	var result = CalcularCRC(DebugMode,DebugEtty,GetProxy().GetCfgResource("start-form-menu"),'ALL','TASK','','','','','','','','','');

		Ctrl("urlPath" ).SetURL("../../../ReportViewer.aspx?ut="+GetProxy().UserToken()+"&file=NucleusWF.Base.Ejecucion.ConsolaCarpetas.rpt&mode=ALL&menu="+GetProxy().GetCfgResource("start-form-menu")+"&DEBUG="+DebugMode+"&DEBUGETTY="+DebugEtty+"&crc="+result.GetAttr('crcCarpeta'));
		RefreshTitle("TASK","");
	}
}


function RefreshDetail(mode,id)
{            
	if (urlDetailMode==mode && urlDetailId==id) 
		return;


	urlDetailMode=mode; urlDetailId=id; g_PASO++;    

	var result = CalcularCRC(DebugMode,DebugEtty,GetProxy().GetCfgResource("start-form-menu"),urlDetailMode,'TASK',urlDetailId,g_DETAIL_LAYOUT,g_PASO,'DETAIL','','','','','');


	switch(urlDetailMode)
	{          
		case "WF":
			break;

		case "INSTANCE":
			Ctrl("urlDetail" ).SetURL("../../../ReportViewer.aspx?ut="+GetProxy().UserToken()+"&file=NucleusWF.Base.Ejecucion.ConsolaInstancia.rpt&mode="+urlDetailMode+"&oi_instance="+urlDetailId+"&DEBUG="+DebugMode+"&DEBUGETTY="+DebugEtty+"&show="+g_DETAIL_LAYOUT+"&paso="+g_PASO+"&crc="+result.GetAttr('crcIntance'));
			break;

		case "THREAD":
			Ctrl("urlDetail" ).SetURL("../../../ReportViewer.aspx?ut="+GetProxy().UserToken()+"&file=NucleusWF.Base.Ejecucion.ConsolaInstancia.rpt&mode="+urlDetailMode+"&oi_thread="+urlDetailId+"&DEBUG="+DebugMode+"&DEBUGETTY="+DebugEtty+"&show="+g_DETAIL_LAYOUT+"&paso="+g_PASO+"&crc="+result.GetAttr('crcThread'));
			break;

		default:
			Ctrl("urlDetail" ).SetURL("../../../ReportViewer.aspx?ut="+GetProxy().UserToken()+"&file=NucleusWF.Base.Ejecucion.ConsolaCarpetas.rpt&mode="+urlDetailMode+"&wf="+urlDetailId+"&style=DETAIL&DEBUG="+DebugMode+"&DEBUGETTY="+DebugEtty+"&show="+g_DETAIL_LAYOUT+"&paso="+g_PASO+"&crc="+result.GetAttr('crcCarpetaDetail'));
			break;
	}
}                     

function CallFlow(ACTION) 
{ 
	var Params, report;
	var Actions=ACTION.split(":");

	switch(Actions)
	{
		case "RPT":
			report=Actions[1].split(".");
			name  =report[report.length-1];
			report.length--; report=report.join(".");
			getFormInMain('Nomad.Base.Report.Report.flow', 'FILTER', '<PARAM report="'+report+'" name="'+name+'" />', false);
			break;

		case "CUBE":
			getFormInMain('Nomad.Cube.flow', 'initialize', '<DATA cube-name="'+Actions[1]+'" />', false);
			break;

		case "SRP":
			getFormInMain('Nomad.Base.Report.Report.flow', 'initialize', '<DATA report="'+Actions[1]+'" />', false);
			break;

		case "VIEW2":
			getFormInMain('Nomad.Base.Report.Cube.flow', 'initialize', '<DATA view-name="'+Actions[1]+'" />', false);
			break;    

		default:
			Params=new NomadXML("PARAMS");

			if (Actions.length>2)
			{
				var values=Actions[2].split("&");
				for (var t=0; t<values.length; t++)
				{    
					if (values[t].indexOf("=")>=0)
						Params.SetAttr(	values[t].substr(0,values[t].indexOf("=")), values[t].substr(values[t].indexOf("=")+1));
				}
			}
			getFormInMain(Actions[0], Actions[1], Params.ToString(), false);
			break;
	}
}


function RefreshReport()
{
	var mode=urlDetailMode;
	var id=urlDetailId;    

	urlDetailId="";
	RefreshDetail(mode,id);
}

function IniciarWF(oi_wf)
{                                                                       
	getFormInMain("NucleusWF.Base.Ejecucion.Formularios.ShowForm.flow", "CREATE", '<DATA oi_wf="'+oi_wf+'" DEBUG="'+DebugMode+'" ETTY="'+DebugEtty+'" />', false);
}

function ShowInstance(oi_instance, oi_thread)
{                                           
	if (oi_thread)
		RefreshDetail("THREAD", oi_thread);
	else
