}

function OpenInstance(oi_instance, oi_thread)
{                    
    var result = CalcularCRC(DebugMode,DebugEtty,GetProxy().GetCfgResource("start-form-menu"),'SHOW','TASK',oi_instance,'N',g_PASO,'DETAIL','','','','','');

	open("./ReportViewer.aspx?ut="+GetProxy().UserToken()+"&file=NucleusWF.Base.Ejecucion.ConsolaInstancia.rpt&mode=SHOW&oi_instance="+oi_instance+"&DEBUG="+DebugMode+"&DEBUGETTY="+DebugEtty+"&show=N&paso="+g_PASO+"&crc="+result.GetAttr('crcIntance'), '', 'channelmode=no,directories=no,fullscreen=no,location=yes,menubar=yes,resizable=yes,scrollbars=yes,status=no,titlebar=yes,toolbar=yes,left=0,top=0,width='+(screen.width-12)+',height='+(screen.height-60));
}

function ClickPlay(oi_instance)
{
	if (!confirm("¿Esta seguro que quiere 'Despausar' el Workflow?")) return;

	var objProxy = new NomadProxy();
	var objRPC = objProxy.RPCService();
	objRPC.AddParam(new NomadRPCParam("oi_instance", "IN", parseInt(oi_instance, 10)));
	objRPC.AddParam(new NomadRPCParam("etty", "IN", DebugEtty));
	objRPC.Execute("NucleusWF.Base.Ejecucion.Instancias.INSTANCE", "Continuar");

	urlDetailId=0;
