	RefreshReport();
}

function GenerateWIKI(strin, parentPath)
{
	var t,d,mode,mode2=0;
	var sections=new Array();
	var new_section=null;
	var mode="";
	var lineas="";
	var text;

	lineas=Replace(strin,"\r\n","\n").split("\n");

	for (t=0; t<lineas.length; t++)
	{
		mylin=lineas[t];

		x=0; mylintrim=mylin;
		while(mylintrim.length>0 && mylintrim.charCodeAt(0)<=32 && mylintrim.charCodeAt(0)>0) { mylintrim=mylintrim.substr(1); x++; }
		mylintrim=Trim(mylintrim)

		if (mode2!=0)
		{
			if (mylintrim=="</code>") mode2=0;
			if (mylintrim=="</file>") mode2=0;
			if (mylintrim=="</nowiki>") mode2=0;
		}

		if (mode2!=0)
				text+=(text!=""?"\n":"")+mylin;

		if (mode2==0)
		{
			if (mylin.length==0)
				new_section=null;
			else
			{
				mode=1; //comun
				if (mylin.substr(0,2)=="  ")
				{
					if ((mylintrim.substr(0,1)!="*") && (mylintrim.substr(0,1)!="-")) mode=2; //CODE
					                                                             else mode=3; //LISTA
				} else
				{
					for (HeadMode=6; HeadMode>0; HeadMode--)
						if ((mylin.substr(0,HeadMode+1)=="======".substr(0,HeadMode)+" ") && (mylin.substr(mylin.length-(HeadMode+1),HeadMode+1)==" "+"======".substr(0,HeadMode)))
							mode=4; //HEAD

					if (mylin.substr(0,4)=="----")
						mode=6; //LINEA

					if (mylin.substr(0,1)==">")
						mode=8; //DIALOGO

					if ((mylin.substr(0,1)=="|") || (mylin.substr(0,1)=="^"))
						mode=9; //TABLA
				}

				if (mode==1)
				{
					if (mylintrim=="<code>")             { mode2= 2; text=""; continue; }
					if (mylintrim.substr(0,6)=="<code ") { mode2= 2; text=""; continue; }
					if (mylintrim=="<file>")             { mode2= 5; text=""; continue; }
					if (mylintrim=="<nowiki>")           { mode2= 7; text=""; continue; }

					if (mylintrim=="</nowiki>") 
					{ 
						mode=7; //CODE
						mylintrim=text;
					}
					if (mylintrim=="</code>") 
					{ 
						mode=2; //CODE
						mylintrim=text;
					}
					if (mylintrim=="</file>")
					{ 
						mode=5; //FILE
						mylintrim=text;
					}
				}

				//controlo que el modo anterior sea igual al actual
				if (new_section!=null)
					if (new_section.mode!=mode) 
						new_section=null; 

				//creo el modo si este no existe
				if (new_section==null)
				{
					new_section=new Object();
					new_section.mode=mode;
					new_section.HTML="";
					new_section.Level=0;
					new_section.Items=null;
					new_section.Start=t;
					new_section.End=t;

					sections[sections.length]=new_section;
				} else
					new_section.End=t;


				//Analizo los distintos modos
				switch(mode)
				{
					case 1: //Texto WIKI
						new_section.HTML+=WIKIEncode(t, x, mylintrim,'parent.Ctrl("'+this.m_ID+'").',"../images/Wiki/")+" ";
					break;
					case 7: //Texto NO WIKI
						new_section.HTML+=HTMLEncode(mylintrim)+" "; 
					break;

					case 2: //Code
					case 5: //File
						new_section.HTML+=(new_section.HTML!=""?"<br/>":"")+HTMLEncode(mylintrim)+" ";
					break;

					case 10: //Nomad Code
						new_section.HTML+=(new_section.HTML!=""?"\n":"")+mylintrim+" ";
					break;

					case 9: //Tabla
						if (new_section.Items==null) new_section.Items=new Array();
						new_section.Items[new_section.Items.length]=mylin;
					break;

					case 8: //Dialogo
						for (d=0; d<mylin.length && mylin.substr(d,1)=='>'; d++);

						newItem=new Object();
						newItem.spaces=d;
						newItem.HTML  =WIKIEncode(t, d, Trim(mylin.substr(d)),'parent.Ctrl("'+this.m_ID+'").',"../images/Wiki/");

						//Agrego el Item
						if (new_section.Items==null) new_section.Items=new Array();
						new_section.Items[new_section.Items.length]=newItem;
					break;

					case 3: //Lista 
						newItem=new Object();
						newItem.spaces=mylin.indexOf(mylintrim);
						newItem.mode  =mylintrim.substr(0,1);
						newItem.HTML  =WIKIEncode(t, newItem.spaces+1, mylintrim.substr(1),'parent.Ctrl("'+this.m_ID+'").',"../images/Wiki/");

						//Agrego el Item
						if (new_section.Items==null) new_section.Items=new Array();
						new_section.Items[new_section.Items.length]=newItem;
					break;

					case 4: //Cabezera
						for (HeadMode=6; HeadMode>0; HeadMode--)
							if ((mylin.substr(0,HeadMode+1)=="======".substr(0,HeadMode)+" ") && (mylin.substr(mylin.length-(HeadMode+1),HeadMode+1)==" "+"======".substr(0,HeadMode)))
							{
								new_section.Level=(7-HeadMode);
								new_section.HTML+=WIKIEncode(t, HeadMode+1, mylin.substr(HeadMode+1,mylin.length-(HeadMode+1)*2),'parent.Ctrl("'+this.m_ID+'").',"../images/Wiki/")+" ";
							}
						new_section=null;
					break;

					case 6: //LINEA
					break;
				}

			}
		}
	}

	///////////////////////////////////////////////////////////////////////////////////////////////////////////////////
	// Genero el HTML
	var HTMLresult="<div class='dokuwiki'>";
	var section,Niveles,n,d,Item,newNivel, divLevel=0, linStart=0;

	for (t=0; t<sections.length; t++)
	{
		section=sections[t];
		switch(section.mode)
		{
				case 1: //Texto WIKI
				case 7: //Texto NO WIKI
					HTMLresult+="<p>"+section.HTML+"</p>";
				break;

				case 2: //Code
					HTMLresult+="<pre class='code' >"+section.HTML+"</pre>";  
				break;

				case 5: //File
					HTMLresult+="<pre class='file' >"+section.HTML+"</pre>";  
				break;

				case 9: //Tabla
					HTMLresult+="<table class='inline' >";  
					for (d=0; d<section.Items.length; d++)
					{
						HTMLresult+="<tr>";

						Item=section.Items[d];

						x=0;
						while (Item.length>1)
						{
							if (Item.substr(0,1)=="^") mode=1;
							if (Item.substr(0,1)=="|") mode=0;

							Item=Item.substr(1); mylin=""; x++; x2=x;
							while (Item.substr(0,1)!="|" && Item.substr(0,1)!="^" && Item.length>0)
							{
								mylin+=Item.substr(0,1); Item=Item.substr(1); x++;
							}

							count=0;
							while ((Item.substr(count,1)=="|" || Item.substr(count,1)=="^") && Item.length>count) count++;
							if (count) { Item=Item.substr(count-1); x+=count-1; }

							HTMLresult+=mode?"<th":"<td";
							if (count>1) HTMLresult+=" colspan='"+count+"' ";        
							if (mylin.substr(0,1)!=" ") HTMLresult+=" class='leftalign' "; else
							if (mylin.substr(mylin.length-1,1)!=" ") HTMLresult+=" class='rightalign' "; else
							if (mylin.substr(0,2)=="  ") HTMLresult+=" align='centeralign' ";

							while(mylin.length>0 && mylin.charCodeAt(0)<=32 && mylin.charCodeAt(0)>0) { mylin=mylin.substr(1); x2++; }

							HTMLresult+=">";
							HTMLresult+=WIKIEncode(section.Start+d, x2, Trim(mylin),'parent.Ctrl("'+this.m_ID+'").',"../images/Wiki/");
							HTMLresult+=mode?"</th>":"</td>";

						}

						HTMLresult+="</tr>";  
					}
					HTMLresult+="</table>";  
				break;

				case 3: //Lista
					Niveles=new Array();
					for (d=0; d<section.Items.length; d++)
					{
						Item=section.Items[d];

						newNivel=null;
						for (n=0; n<Niveles.length; n++)
						{
							if (Niveles[n].spaces>Item.spaces)
							{
								while (Niveles.length>n)
								{
									if (Niveles[Niveles.length-1].mode=="*") HTMLresult+="</ul>";
									if (Niveles[Niveles.length-1].mode=="-") HTMLresult+="</ol>";
									Niveles.length--;
								}
							} else
							if (Niveles[n].spaces==Item.spaces)
								newNivel=Niveles[n];
						}

						if (newNivel==null)
						{
							Niveles[Niveles.length]=newNivel=Item;
							if (newNivel.mode=="*") HTMLresult+="<ul>";
							if (newNivel.mode=="-") HTMLresult+="<ol>";
						}
						HTMLresult+="<li><div class='li'>"+Item.HTML+"</div></li>";
					}
					while (Niveles.length>0)
					{   
						if (Niveles[Niveles.length-1].mode=="*") HTMLresult+="</ul>";
						if (Niveles[Niveles.length-1].mode=="-") HTMLresult+="</ol>";
						Niveles.length--;
					}

				break;

				case 8: //Dialogo 
					Niveles=0;

					for (d=0; d<section.Items.length; d++)
					{
						Item=section.Items[d];

						while(Niveles>Item.spaces)
						{
								HTMLresult+="</div></blockquote>";
								Niveles--;
						}

						while(Niveles<Item.spaces)
						{
								HTMLresult+="<blockquote><div class='no'>";
								Niveles++;
						}
						HTMLresult+=Item.HTML;
					}

					while (Niveles>0)
					{   
						HTMLresult+="</div></blockquote>";
						Niveles--;
					}
				break;

				case 4: //Cabecera
					if (divLevel!=0) HTMLresult+="</div></div>";
					divLevel=section.Level;
					linStart=section.Start;
					HTMLresult+="<div class='secedit' >";
					HTMLresult+="<H"+divLevel+">"+section.HTML+"</H"+divLevel+">";
					HTMLresult+="<div class='level"+divLevel+"' >";
				break;

				case 6: //Linea
					HTMLresult+="<hr/>";
				break;
		}
	}

	if (divLevel!=0) HTMLresult+="</div></div>";
	HTMLresult+="</div>";


	return HTMLresult;
}
